        NEXT: { target: 'password', guard: 'emailValid' }
      }
    },
    password: {
      on: {
        SET_PASSWORD: { actions: assign({ password: ({ event }) => event.value }) },
        NEXT: { target: 'confirm', guard: 'passwordValid' },
