import { setup, assign, fromPromise } from 'xstate';

type Ctx = { email: string; error?: string };
type Ev = { type: 'SET_EMAIL'; value: string } | { type: 'SUBMIT' };

const checkEmail = fromPromise<boolean, { email: string }>(async ({ input }) => {
  const res = await fetch('/api/email-available?e=' + encodeURIComponent(input.email));
  const data = (await res.json()) as { available: boolean };
  return data.available;
});

export const signupMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { checkEmail },
  guards: {
    hasAt: ({ context }) => context.email.includes('@')
  }
}).createMachine({
  id: 'signupUnique',
  initial: 'editing',
  context: { email: '' },
  states: {
    editing: {
      on: {
        SET_EMAIL: { actions: assign({ email: ({ event }) => event.value }) },
        SUBMIT: { target: 'checking', guard: 'hasAt' }
      }
    },
    checking: {
      invoke: {
        src: 'checkEmail',
        input: ({ context }) => ({ email: context.email }),
        onDone: [
          { target: 'done', guard: ({ event }) => event.output === true },
          { target: 'taken' }
        ],
        onError: {
          target: 'editing',
          actions: assign({ error: () => 'Network error' })
        }
      }
    },
    taken: { on: { SET_EMAIL: { target: 'editing', actions: assign({ email: ({ event }) => event.value }) } } },
    done: { type: 'final' }
  }
});
