A multi-step form in XState v5 models each step as a child state inside a parent compound state. `setup({ types })` locks context and events, guards gate NEXT transitions, and BACK transitions return to the previous step. A `final` state marks completion and can emit `output` consumed by the invoking parent.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { name: string; plan: 'free' | 'pro'; tos: boolean };
type Ev =
  | { type: 'SET_NAME'; value: string }
  | { type: 'SET_PLAN'; value: 'free' | 'pro' }
  | { type: 'ACCEPT_TOS' }
  | { type: 'NEXT' }
  | { type: 'BACK' };

export const wizardMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev, output: {} as { user: Ctx } },
  guards: {
    hasName: ({ context }) => context.name.trim().length > 0,
    tosOk: ({ context }) => context.tos
  }
}).createMachine({
  id: 'wizard',
  initial: 'name',
  context: { name: '', plan: 'free', tos: false },
  output: ({ context }) => ({ user: context }),
  states: {
    name: {
      on: {
        SET_NAME: { actions: assign({ name: ({ event }) => event.value }) },
        NEXT: { target: 'plan', guard: 'hasName' }
      }
    },
    plan: {
      on: {
        SET_PLAN: { actions: assign({ plan: ({ event }) => event.value }) },
        NEXT: 'review',
        BACK: 'name'
      }
    },
    review: {
      on: {
        ACCEPT_TOS: { actions: assign({ tos: () => true }) },
        NEXT: { target: 'done', guard: 'tosOk' },
        BACK: 'plan'
      }
    },
    done: { type: 'final' }
  }
});
```

