import { setup, assign } from 'xstate';

type Ctx = { email: string; password: string; confirm: string };
type Ev =
  | { type: 'FIELD'; field: 'email' | 'password' | 'confirm'; value: string }
  | { type: 'SUBMIT' };
type Out = { email: string };

export const signupStrict = setup({
  types: { context: {} as Ctx, events: {} as Ev, output: {} as Out },
  guards: {
    emailOk: ({ context }) => /.+@.+\..+/.test(context.email),
    passwordOk: ({ context }) => context.password.length >= 8,
    matches: ({ context }) => context.password === context.confirm && context.password.length > 0
  }
}).createMachine({
  id: 'signupStrict',
  initial: 'editing',
  context: { email: '', password: '', confirm: '' },
  output: ({ context }) => ({ email: context.email }),
  states: {
    editing: {
      on: {
        FIELD: {
          actions: assign(({ context, event }) => ({ ...context, [event.field]: event.value }))
        },
        SUBMIT: [
          { target: 'invalidEmail', guard: ({ context }) => !/.+@.+\..+/.test(context.email) },
          { target: 'invalidPassword', guard: ({ context }) => context.password.length < 8 },
          { target: 'mismatch', guard: ({ context }) => context.password !== context.confirm },
          { target: 'done' }
        ]
      }
    },
    invalidEmail: { on: { FIELD: { target: 'editing', actions: assign(({ context, event }) => ({ ...context, [event.field]: event.value })) } } },
    invalidPassword: { on: { FIELD: { target: 'editing', actions: assign(({ context, event }) => ({ ...context, [event.field]: event.value })) } } },
    mismatch: { on: { FIELD: { target: 'editing', actions: assign(({ context, event }) => ({ ...context, [event.field]: event.value })) } } },
    done: { type: 'final' }
  }
});
