import { setup, assign, fromPromise } from 'xstate';

type Ctx = { data: unknown; error: string | null; attempt: number };
type Ev = { type: 'FETCH' } | { type: 'RETRY' } | { type: 'CANCEL' };

const getData = fromPromise<unknown, { url: string }>(async ({ input }) => {
  const r = await fetch(input.url);
  if (!r.ok) throw new Error('HTTP ' + r.status);
  return r.json();
});

export const fetchRetry = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { getData },
  delays: {
    backoff: ({ context }) => Math.min(30_000, 500 * 2 ** context.attempt)
  },
  guards: {
    canRetry: ({ context }) => context.attempt < 3
  }
}).createMachine({
  id: 'fetchRetry',
  initial: 'idle',
  context: { data: null, error: null, attempt: 0 },
  states: {
    idle: { on: { FETCH: 'loading' } },
    loading: {
      invoke: {
        src: 'getData',
        input: () => ({ url: '/api/resource' }),
        onDone: {
          target: 'success',
          actions: assign({ data: ({ event }) => event.output, error: () => null, attempt: () => 0 })
        },
        onError: [
          {
            target: 'waiting',
            guard: 'canRetry',
            actions: assign({
              error: ({ event }) => (event.error instanceof Error ? event.error.message : 'err'),
              attempt: ({ context }) => context.attempt + 1
            })
          },
          {
            target: 'failed',
            actions: assign({
              error: ({ event }) => (event.error instanceof Error ? event.error.message : 'err')
            })
          }
        ]
      }
    },
    waiting: {
      after: { backoff: { target: 'loading' } },
      on: { CANCEL: 'failed' }
    },
    success: { type: 'final' },
    failed: { on: { RETRY: { target: 'loading', actions: assign({ attempt: () => 0 }) } } }
  }
});
```

