`fromCallback` wraps an imperative subscription as an actor. The callback receives `sendBack` (push events to the parent) and `receive` (subscribe to parent-sent events), and returns a cleanup function called on stop. Events pushed via `sendBack` appear in the parent's `on:` handlers like any other event.

```typescript
import { setup, assign, fromCallback } from 'xstate';

type Ctx = { online: boolean };
type Ev = { type: 'ONLINE' } | { type: 'OFFLINE' };

const connectivity = fromCallback<Ev>(({ sendBack }) => {
  const on = () => sendBack({ type: 'ONLINE' });
  const off = () => sendBack({ type: 'OFFLINE' });
  window.addEventListener('online', on);
  window.addEventListener('offline', off);
  return () => {
    window.removeEventListener('online', on);
    window.removeEventListener('offline', off);
  };
});

export const netMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { connectivity }
}).createMachine({
  id: 'net',
  context: { online: true },
  invoke: { src: 'connectivity' },
  on: {
    ONLINE: { actions: assign({ online: () => true }) },
    OFFLINE: { actions: assign({ online: () => false }) }
  }
});
```

