import { setup, assign, enqueueActions, fromPromise } from 'xstate';

type Ctx = { ok: boolean; err: string | null };
type Ev = { type: 'SUBMIT' };

const charge = fromPromise<void, void>(async () => {
  await fetch('/c', { method: 'POST' });
