export const p = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { charge },
  guards: {
    clean: ({ context }) => context.err === null
  },
  actions: {
    prepareCharge: enqueueActions(({ enqueue, check }) => {
      if (check('clean')) {
        enqueue.assign({ ok: false, err: null });
      }
    })
  }
}).createMachine({
  id: 'p',
  initial: 'idle',
  context: { ok: false, err: null },
  states: {
    idle: {
      on: {
        SUBMIT: { target: 'charging', guard: 'clean', actions: 'prepareCharge' }
      }
    },
    charging: {
      invoke: {
        src: 'charge',
        onDone: { target: 'done', actions: assign({ ok: () => true }) },
        onError: { target: 'idle', actions: assign({ err: () => 'failed' }) }
      }
    },
    done: { type: 'final' }
  }
});
