import { setup, assign, fromPromise } from 'xstate';

type Ctx = { amount: number; chargeId: string | null; error: string | null };
type Ev = { type: 'PAY'; amount: number };
type Out = { chargeId: string; amount: number } | { error: string };

const charge = fromPromise<{ id: string }, { amount: number }>(async ({ input }) => {
  const r = await fetch('/charge', { method: 'POST', body: JSON.stringify(input) });
  if (!r.ok) throw new Error('HTTP ' + r.status);
  return (await r.json()) as { id: string };
});

export const payWithOutput = setup({
  types: { context: {} as Ctx, events: {} as Ev, output: {} as Out },
  actors: { charge }
}).createMachine({
  id: 'payWithOutput',
  initial: 'idle',
  context: { amount: 0, chargeId: null, error: null },
  output: ({ context }) => {
    if (context.chargeId !== null) return { chargeId: context.chargeId, amount: context.amount };
    return { error: context.error ?? 'unknown' };
  },
  states: {
    idle: {
      on: {
        PAY: { target: 'charging', actions: assign({ amount: ({ event }) => event.amount }) }
      }
    },
    charging: {
      invoke: {
        src: 'charge',
        input: ({ context }) => ({ amount: context.amount }),
        onDone: { target: 'done', actions: assign({ chargeId: ({ event }) => event.output.id }) },
        onError: {
          target: 'done',
          actions: assign({
            error: ({ event }) => (event.error instanceof Error ? event.error.message : 'err')
          })
        }
      }
    },
    done: { type: 'final' }
  }
});
